package lec1;

public class odd_even {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int n=7;
//		System.out.println(n);
		if(n>5) {
			System.out.println("hello");
		}
		if(n%2==0) {
			System.out.println("even");
		}
		else {
			System.out.println("odd");
		}

	}

}
